# %% ../05_memorytools.ipynb 25
def create_traced_tool(func, memory=None, name=None, trace_level=1):
    "Create a traced version of a tool function that logs execution details"
    func_name = name or func.__name__
    
    def traced_wrapper(*args, **kwargs):
        start_time = time.time()
        print(f"[TOOL START] {func_name} called with args: {args}, kwargs: {kwargs}")
        
        try:
            if memory and memory.debug and memory.debug_level >= trace_level:
                memory._debug(f"Tool '{func_name}' executing", level=trace_level)
                
            result = func(*args, **kwargs)
            
            duration = time.time() - start_time
            print(f"[TOOL END] {func_name} completed in {duration:.4f}s")
            
            if memory and memory.debug and memory.debug_level >= trace_level:
                memory._debug(f"Tool '{func_name}' completed in {duration:.4f}s", 
                             level=trace_level, data=result, show_data=trace_level > 1)
                
            return result
            
        except Exception as e:
            duration = time.time() - start_time
            print(f"[TOOL ERROR] {func_name} failed after {duration:.4f}s: {str(e)}")
            if memory and memory.debug:
                memory._debug(f"Tool '{func_name}' failed: {str(e)}", level=1)
            raise
            
    traced_wrapper.__name__ = func.__name__
    traced_wrapper.__doc__ = func.__doc__
    traced_wrapper.__annotations__ = func.__annotations__
    
    return traced_wrapper

# %% ../05_memorytools.ipynb 26
def create_traced_toolset(tools, memory=None, trace_level=1):
    "Create traced versions of all tools in a toolset"
    if isinstance(tools, list):
        return [create_traced_tool(tool, memory, trace_level=trace_level) for tool in tools]
    elif isinstance(tools, dict):
        return {name: create_traced_tool(func, memory, name, trace_level=trace_level) 
                for name, func in tools.items()}
    else:
        raise ValueError("Tools must be a list or dictionary")

# %% ../05_memorytools.ipynb 27
def create_memory_tracer(memory=None, log_file=None, include_content=True):
    "Create a tracer function for Claude's toolloop that integrates with memory debugging"
    
    def memory_tracer(data):
        timestamp = datetime.now().isoformat()
        
        # Log to console
        print(f"[CLAUDE {timestamp}]")
        
        # Extract relevant parts based on message type
        if isinstance(data, list) and len(data) > 0 and isinstance(data[0], dict):
            for msg in data:
                role = msg.get('role', 'unknown')
                
                if role == 'assistant' and 'content' in msg:
                    content = msg['content']
                    if include_content:
                        if isinstance(content, list):
                            for item in content:
                                if hasattr(item, 'text'):
                                    print(f"  [ASSISTANT TEXT] {item.text[:100]}...")
                                elif hasattr(item, 'type') and item.type == 'tool_use':
                                    print(f"  [TOOL USE] {item.name} with input: {item.input}")
                        else:
                            print(f"  [ASSISTANT] {str(content)[:100]}...")
                    else:
                        print(f"  [ASSISTANT] Content length: {len(str(content))}")
                
                elif role == 'user' and 'content' in msg:
                    content = msg.get('content', [])
                    if isinstance(content, list):
                        for item in content:
                            if item.get('type') == 'tool_result':
                                print(f"  [TOOL RESULT] ID: {item.get('tool_use_id')} Result: {item.get('content')[:50]}...")
                            elif item.get('type') == 'text':
                                print(f"  [USER TEXT] {item.get('text', '')[:100]}...")
                    else:
                        print(f"  [USER] {str(content)[:100]}...")
        
        # Log to memory debug if available
        if memory and memory.debug:
            memory._debug(f"Claude interaction", level=1, data=data, show_data=False)
            
        # Log to file if provided
        if log_file:
            with open(log_file, 'a') as f:
                f.write(f"--- {timestamp} ---\n")
                f.write(json.dumps(data, default=str, indent=2))
                f.write("\n\n")
    
    return memory_tracer

# %% ../05_memorytools.ipynb 28
def create_memory_chat(memory, tools, model="claude-3-7-sonnet-20250219", trace_level=1, log_file=None):
    "Create a Claude chat with traced tools and memory integration"
    traced_tools = create_traced_toolset(tools, memory, trace_level)
    
    if isinstance(traced_tools, dict):
        tool_list = list(traced_tools.values())
    else:
        tool_list = traced_tools
        
    chat = Chat(model=model, tools=tool_list)
    
    # Store memory reference and tracer for later use
    chat.memory = memory
    chat.memory_tracer = create_memory_tracer(memory, log_file)
    
    # Add a convenience method for memory-aware toolloop
    def memory_toolloop(prompt, **kwargs):
        if 'trace_func' not in kwargs:
            kwargs['trace_func'] = chat.memory_tracer
        return chat.toolloop(prompt, **kwargs)
        
    chat.memory_toolloop = memory_toolloop
    
    return chat

