def create_memory_exploration_tools(memory):
    "Create a set of basic tools for exploring semantic memory"
    
    def list_entity_types() -> list:
        "List all entity types in the memory with counts"
        return [(t, len(entities)) for t, entities in memory.indices.by_type.items()]
    
    def find_entities_by_type(type_uri: str) -> list:
        "Find all entities of a specific type"
        entities = memory.query_by_type(type_uri)
        return [e.get("@id") for e in entities if "@id" in e]
    
    def get_entity(entity_id: str) -> dict:
        "Get details of a specific entity"
        entity = memory.query_by_id(entity_id)
        if not entity: return {"error": f"Entity {entity_id} not found"}
        
        # Create a simplified version for the LLM
        result = {"id": entity_id, "type": entity.get("@type", [])}
        
        # Add simplified properties
        for prop, values in entity.items():
            if prop.startswith("@"): continue
            
            # Extract simple values from the property
            simple_values = []
            for val in values if isinstance(values, list) else [values]:
                if isinstance(val, dict):
                    if "@value" in val: simple_values.append(val["@value"])
                    elif "@id" in val: simple_values.append({"id": val["@id"]})
                else:
                    simple_values.append(val)
            
            # Use the short name for the property
            prop_name = prop.split("/")[-1]
            result[prop_name] = simple_values
            
        return result
    
    def find_relationships(entity_id: str) -> dict:
        "Find relationships to and from an entity"
        entity = memory.query_by_id(entity_id)
        if not entity: return {"error": f"Entity {entity_id} not found"}
        
        outgoing = []
        for prop, values in entity.items():
            if prop.startswith("@"): continue
            
            for val in values if isinstance(values, list) else [values]:
                if isinstance(val, dict) and "@id" in val:
                    outgoing.append({
                        "property": prop,
                        "target": val["@id"]
                    })
        
        # Find incoming relationships (simplified approach)
        incoming = []
        for other_id, other in memory.indices.by_id.items():
            if other_id == entity_id: continue
            
            for prop, values in other.items():
                if prop.startswith("@"): continue
                
                for val in values if isinstance(values, list) else [values]:
                    if isinstance(val, dict) and "@id" in val and val["@id"] == entity_id:
                        incoming.append({
                            "source": other_id,
                            "property": prop
                        })
        
        return {
            "entity": entity_id,
            "outgoing": outgoing,
            "incoming": incoming
        }
    
    def search_entities(query: str, limit: int = 5) -> list:
        "Search for entities matching a text query"
        results = memory.search(query, limit)
        return [{"id": e.get("@id"), "type": e.get("@type", [])} 
                for e in results if "@id" in e]
    
    return {
        "list_entity_types": list_entity_types,
        "find_entities_by_type": find_entities_by_type,
        "get_entity": get_entity,
        "find_relationships": find_relationships,
        "search_entities": search_entities
    }

